var COURSE_PL_JA = [{day: 1, title: `Pierwsze powitania w Tokio`, title_native: `東京でのあいさつ`, focus: `Nauczysz się najprostszych powitań i zwrotów grzecznościowych. Wyobraź sobie, że właśnie wychodzisz z dworca Tokyo Station i chcesz uprzejmie zacząć pierwszą rozmowę.`, vocab: [{ja: `こんにちは`, pl: `dzień dobry / cześć`, ipa: `kon-ni-czi-wa`},{ja: `おはようございます`, pl: `dzień dobry rano`, ipa: `o-ha-jo-o go-za-i-mas`},{ja: `こんばんは`, pl: `dobry wieczór`, ipa: `kon-ban-wa`},{ja: `ありがとう`, pl: `dziękuję`, ipa: `a-ri-ga-to-o`},{ja: `ありがとうございます`, pl: `dziękuję bardzo`, ipa: `a-ri-ga-to-o go-za-i-mas`},{ja: `すみません`, pl: `przepraszam / proszę o uwagę`, ipa: `su-mi-ma-sen`},{ja: `はい`, pl: `tak`, ipa: `haj`},{ja: `いいえ`, pl: `nie`, ipa: `ii-e`},{ja: `さようなら`, pl: `do widzenia`, ipa: `sa-jo-o-na-ra`},{ja: `またね`, pl: `do zobaczenia`, ipa: `ma-ta-ne`}], phrases: [{ja: `こんにちは。`, pl: `Dzień dobry.`, ipa: `kon-ni-czi-wa`},{ja: `ありがとうございます。`, pl: `Dziękuję bardzo.`, ipa: `a-ri-ga-to-o go-za-i-mas`},{ja: `すみません。`, pl: `Przepraszam.`, ipa: `su-mi-ma-sen`},{ja: `はい、そうです。`, pl: `Tak, zgadza się.`, ipa: `haj, so-o des`},{ja: `いいえ、ちがいます。`, pl: `Nie, to nie tak.`, ipa: `ii-e, czi-ga-i-mas`},{ja: `またあとで。`, pl: `Do zobaczenia później.`, ipa: `ma-ta a-to-de`}], grammar: `W japońskim często pomija się podmiot, jeśli wiadomo, o kim mowa. Zwrot こんにちは sam w sobie wystarczy jako uprzejme powitanie. ございます dodaje grzeczności, dlatego ありがとうございます brzmi bardziej formalnie niż ありがとう. W podróży bezpieczniej jest zaczynać od form grzecznych.`, practice: [`Powiedz po japońsku „Dzień dobry”.`,`Powiedz po japońsku „Dziękuję bardzo”.`,`Wyobraź sobie, że chcesz zwrócić uwagę pracownika stacji. Jak powiesz „przepraszam”?`,`Odpowiedz „tak” i „nie” po japońsku.`,`Ułóż krótkie pożegnanie z użyciem またね.`]},{day: 2, title: `Przedstawianie się w Kioto`, title_native: `京都での自己紹介`, focus: `Nauczysz się podawać imię i mówić, że jesteś z Polski. Przyda się to w hostelu, podczas wycieczki lub przy poznawaniu lokalnych osób w Kioto.`, vocab: [{ja: `わたし`, pl: `ja`, ipa: `wa-ta-si`},{ja: `名前`, pl: `imię`, ipa: `na-ma-e`},{ja: `ポーランド`, pl: `Polska`, ipa: `po-o-ran-do`},{ja: `日本`, pl: `Japonia`, ipa: `ni-hon`},{ja: `人`, pl: `osoba / człowiek`, ipa: `dźin`},{ja: `旅行者`, pl: `podróżny`, ipa: `rjo-ko-o-sza`},{ja: `学生`, pl: `student`, ipa: `ga-ku-se-e`},{ja: `会社員`, pl: `pracownik firmy`, ipa: `ka-i-sza-in`},{ja: `よろしく`, pl: `miło mi / proszę o życzliwość`, ipa: `jo-ro-si-ku`},{ja: `はじめまして`, pl: `miło poznać`, ipa: `ha-dźi-me-ma-szi-te`}], phrases: [{ja: `はじめまして。`, pl: `Miło poznać.`, ipa: `ha-dźi-me-ma-szi-te`},{ja: `わたしはアンナです。`, pl: `Jestem Anna.`, ipa: `wa-ta-si wa an-na des`},{ja: `ポーランドから来ました。`, pl: `Przyjechałem/przyjechałam z Polski.`, ipa: `po-o-ran-do ka-ra ki-ma-szi-ta`},{ja: `わたしは旅行者です。`, pl: `Jestem podróżnym.`, ipa: `wa-ta-si wa rjo-ko-o-sza des`},{ja: `よろしくお願いします。`, pl: `Miło mi / proszę o życzliwość.`, ipa: `jo-ro-si-ku o-ne-ga-i szi-mas`},{ja: `あなたの名前は何ですか。`, pl: `Jak masz na imię?`, ipa: `a-na-ta no na-ma-e wa nan des ka`}], grammar: `Partykuła は wymawiana jako „wa” oznacza temat zdania. W zdaniu わたしはアンナです mówisz dosłownie: „jeśli chodzi o mnie, Anna jestem”. です dodaje uprzejmy ton i działa podobnie do „jestem/jest/to jest”. Formuła はじめまして jest standardowa przy pierwszym spotkaniu.`, practice: [`Przedstaw się po japońsku, używając swojego imienia.`,`Powiedz „Jestem z Polski” w naturalnej formie podróżnej.`,`Zapytaj kogoś o imię.`,`Połącz はじめまして z よろしくお願いします.`,`Zmień zdanie わたしは旅行者です na zdanie o studencie lub pracowniku firmy.`]},{day: 3, title: `Liczby i ceny w Osace`, title_native: `大阪での数字と値段`, focus: `Nauczysz się liczb potrzebnych do płacenia, zamawiania i pytania o ceny. W Osace przyda się to na targu Kuromon Ichiba i w sklepach z przekąskami.`, vocab: [{ja: `一`, pl: `jeden`, ipa: `iczi`},{ja: `二`, pl: `dwa`, ipa: `ni`},{ja: `三`, pl: `trzy`, ipa: `san`},{ja: `四`, pl: `cztery`, ipa: `jon`},{ja: `五`, pl: `pięć`, ipa: `go`},{ja: `六`, pl: `sześć`, ipa: `roku`},{ja: `七`, pl: `siedem`, ipa: `nana`},{ja: `八`, pl: `osiem`, ipa: `haczi`},{ja: `九`, pl: `dziewięć`, ipa: `kjuu`},{ja: `十`, pl: `dziesięć`, ipa: `dźuu`}], phrases: [{ja: `一つください。`, pl: `Poproszę jedną sztukę.`, ipa: `hi-to-cu ku-da-sa-i`},{ja: `二つください。`, pl: `Poproszę dwie sztuki.`, ipa: `fu-ta-cu ku-da-sa-i`},{ja: `いくらですか。`, pl: `Ile to kosztuje?`, ipa: `i-ku-ra des ka`},{ja: `三百円です。`, pl: `To kosztuje trzysta jenów.`, ipa: `san-bjaku en des`},{ja: `これをください。`, pl: `Poproszę to.`, ipa: `ko-re o ku-da-sa-i`},{ja: `高いです。`, pl: `To jest drogie.`, ipa: `ta-ka-i des`}], grammar: `Do liczenia małych rzeczy często używa się specjalnych liczebników: 一つ, 二つ, 三つ. To bardzo praktyczne, gdy wskazujesz jedzenie, bilety lub pamiątki. 円 oznacza jena i czyta się „en”. Pytanie いくらですか jest krótkie, uprzejme i bardzo przydatne.`, practice: [`Powiedz po japońsku liczby od 1 do 10.`,`Poproś o jedną sztukę jedzenia.`,`Poproś o dwie sztuki pamiątki.`,`Zapytaj „Ile to kosztuje?”.`,`Powiedz, że coś kosztuje 300 jenów.`]},{day: 4, title: `Podstawowe pytania na stacji w Jokohamie`, title_native: `横浜駅での基本質問`, focus: `Nauczysz się zadawać proste pytania z użyciem 何, どこ i いつ. Przyda się to na dużych stacjach, gdzie trzeba szybko znaleźć peron, wyjście lub godzinę odjazdu.`, vocab: [{ja: `何`, pl: `co`, ipa: `nan / nani`},{ja: `どこ`, pl: `gdzie`, ipa: `do-ko`},{ja: `いつ`, pl: `kiedy`, ipa: `i-cu`},{ja: `駅`, pl: `stacja`, ipa: `e-ki`},{ja: `出口`, pl: `wyjście`, ipa: `de-gu-czi`},{ja: `入口`, pl: `wejście`, ipa: `i-ri-gu-czi`},{ja: `電車`, pl: `pociąg`, ipa: `den-sza`},{ja: `バス`, pl: `autobus`, ipa: `ba-su`},{ja: `時間`, pl: `czas / godzina`, ipa: `dźi-kan`},{ja: `切符`, pl: `bilet`, ipa: `kip-pu`}], phrases: [{ja: `駅はどこですか。`, pl: `Gdzie jest stacja?`, ipa: `e-ki wa do-ko des ka`},{ja: `出口はどこですか。`, pl: `Gdzie jest wyjście?`, ipa: `de-gu-czi wa do-ko des ka`},{ja: `これは何ですか。`, pl: `Co to jest?`, ipa: `ko-re wa nan des ka`},{ja: `電車はいつですか。`, pl: `Kiedy jest pociąg?`, ipa: `den-sza wa i-cu des ka`},{ja: `切符はどこですか。`, pl: `Gdzie są bilety?`, ipa: `kip-pu wa do-ko des ka`},{ja: `バスはどこですか。`, pl: `Gdzie jest autobus?`, ipa: `ba-su wa do-ko des ka`}], grammar: `Pytania w języku japońskim często kończą się partykułą か. Nie trzeba zmieniać szyku zdania tak jak w polskim. Wystarczy dodać słowo pytające, na przykład どこ, oraz ですか. Intonacja może lekko rosnąć, ale sama partykuła か jasno pokazuje pytanie.`, practice: [`Zapytaj, gdzie jest wyjście.`,`Zapytaj, co to jest.`,`Zapytaj, kiedy jest pociąg.`,`Zamień 駅 na バス w pytaniu o lokalizację.`,`Wskaż rzecz w wyobraźni i zapytaj: „Co to jest?”.`]},{day: 5, title: `Prośby i uprzejmość w sklepie`, title_native: `店でのお願い`, focus: `Nauczysz się prosić o rzeczy w uprzejmy sposób. W japońskich sklepach i konbini, takich jak 7-Eleven czy Lawson, krótka grzeczna prośba bardzo ułatwia kontakt.`, vocab: [{ja: `これ`, pl: `to tutaj`, ipa: `ko-re`},{ja: `それ`, pl: `to tam przy tobie`, ipa: `so-re`},{ja: `あれ`, pl: `tamto`, ipa: `a-re`},{ja: `水`, pl: `woda`, ipa: `mi-zu`},{ja: `お茶`, pl: `herbata`, ipa: `o-czia`},{ja: `コーヒー`, pl: `kawa`, ipa: `ko-o-hii`},{ja: `袋`, pl: `torba`, ipa: `fu-ku-ro`},{ja: `レシート`, pl: `paragon`, ipa: `re-szii-to`},{ja: `お願いします`, pl: `proszę`, ipa: `o-ne-ga-i szi-mas`},{ja: `ください`, pl: `proszę dać`, ipa: `ku-da-sa-i`}], phrases: [{ja: `これをください。`, pl: `Poproszę to.`, ipa: `ko-re o ku-da-sa-i`},{ja: `水をください。`, pl: `Poproszę wodę.`, ipa: `mi-zu o ku-da-sa-i`},{ja: `袋をお願いします。`, pl: `Poproszę torbę.`, ipa: `fu-ku-ro o-ne-ga-i szi-mas`},{ja: `レシートをください。`, pl: `Poproszę paragon.`, ipa: `re-szii-to o ku-da-sa-i`},{ja: `それもください。`, pl: `Poproszę też to.`, ipa: `so-re mo ku-da-sa-i`},{ja: `お願いします。`, pl: `Proszę.`, ipa: `o-ne-ga-i szi-mas`}], grammar: `を oznacza obiekt czynności i wymawia się „o”. W zdaniu 水をください prosisz dosłownie: „wodę proszę dać”. ください jest bardzo użyteczne przy zamawianiu i kupowaniu. も oznacza „też”, więc それもください znaczy „poproszę też to”.`, practice: [`Poproś o wodę.`,`Poproś o paragon.`,`Wskaż coś blisko siebie i powiedz „Poproszę to”.`,`Dodaj も, aby powiedzieć „też to”.`,`Poproś o torbę, używając お願いします.`]},{day: 6, title: `Dni, godziny i plany w Narze`, title_native: `奈良での日にちと時間`, focus: `Nauczysz się mówić o godzinach i prostych planach. Przyda się to przy umawianiu zwiedzania świątyń w Narze lub sprawdzaniu godzin otwarcia.`, vocab: [{ja: `今日`, pl: `dziś`, ipa: `kjo-o`},{ja: `明日`, pl: `jutro`, ipa: `a-si-ta`},{ja: `昨日`, pl: `wczoraj`, ipa: `kino-o`},{ja: `朝`, pl: `rano`, ipa: `a-sa`},{ja: `昼`, pl: `południe / dzień`, ipa: `hi-ru`},{ja: `夜`, pl: `noc / wieczór`, ipa: `jo-ru`},{ja: `一時`, pl: `pierwsza godzina`, ipa: `iczi-dźi`},{ja: `二時`, pl: `druga godzina`, ipa: `ni-dźi`},{ja: `半`, pl: `pół`, ipa: `han`},{ja: `今`, pl: `teraz`, ipa: `i-ma`}], phrases: [{ja: `今、何時ですか。`, pl: `Która jest teraz godzina?`, ipa: `i-ma, nan-dźi des ka`},{ja: `一時です。`, pl: `Jest pierwsza.`, ipa: `iczi-dźi des`},{ja: `二時半です。`, pl: `Jest druga trzydzieści.`, ipa: `ni-dźi han des`},{ja: `明日行きます。`, pl: `Pójdę jutro.`, ipa: `a-si-ta i-ki-mas`},{ja: `今日見ます。`, pl: `Zobaczę to dziś.`, ipa: `kjo-o mi-mas`},{ja: `朝に行きます。`, pl: `Pójdę rano.`, ipa: `a-sa ni i-ki-mas`}], grammar: `時 oznacza godzinę, a 半 oznacza „pół”. 二時半 to dosłownie „druga godzina i pół”. Czas można stawiać na początku zdania, na przykład 明日行きます. Partykuła に często wskazuje konkretny czas, ale przy 今日 i 明日 bywa pomijana.`, practice: [`Zapytaj, która jest godzina.`,`Powiedz „Jest pierwsza”.`,`Powiedz „Jest druga trzydzieści”.`,`Powiedz, że pójdziesz jutro.`,`Powiedz, że pójdziesz rano.`]},{day: 7, title: `Kierunki i lokalizacja w Sapporo`, title_native: `札幌での方向と場所`, focus: `Nauczysz się rozumieć podstawowe wskazówki kierunku. W Sapporo, przy szerokich ulicach i stacjach metra, te słowa pomogą ci znaleźć drogę.`, vocab: [{ja: `右`, pl: `prawo`, ipa: `migi`},{ja: `左`, pl: `lewo`, ipa: `hidari`},{ja: `まっすぐ`, pl: `prosto`, ipa: `mas-su-gu`},{ja: `ここ`, pl: `tutaj`, ipa: `ko-ko`},{ja: `そこ`, pl: `tam przy tobie`, ipa: `so-ko`},{ja: `あそこ`, pl: `tam dalej`, ipa: `a-so-ko`},{ja: `近い`, pl: `blisko`, ipa: `czi-ka-i`},{ja: `遠い`, pl: `daleko`, ipa: `to-o-i`},{ja: `前`, pl: `przed`, ipa: `ma-e`},{ja: `後ろ`, pl: `za`, ipa: `u-szi-ro`}], phrases: [{ja: `右に行ってください。`, pl: `Proszę iść w prawo.`, ipa: `migi ni it-te ku-da-sa-i`},{ja: `左に行ってください。`, pl: `Proszę iść w lewo.`, ipa: `hidari ni it-te ku-da-sa-i`},{ja: `まっすぐ行ってください。`, pl: `Proszę iść prosto.`, ipa: `mas-su-gu it-te ku-da-sa-i`},{ja: `ここはどこですか。`, pl: `Gdzie jesteśmy?`, ipa: `ko-ko wa do-ko des ka`},{ja: `駅は近いですか。`, pl: `Czy stacja jest blisko?`, ipa: `e-ki wa czi-ka-i des ka`},{ja: `あそこです。`, pl: `To tam dalej.`, ipa: `a-so-ko des`}], grammar: `に przy kierunkach wskazuje, dokąd wykonuje się ruch: 右に, 左に. Forma 行ってください znaczy „proszę iść” i jest bardzo praktyczna, gdy ktoś daje ci instrukcje. Przymiotniki 近い i 遠い kończą się na い, więc mogą same stać przed です.`, practice: [`Powiedz „Proszę iść prosto”.`,`Zapytaj, czy stacja jest blisko.`,`Powiedz „To tam dalej”.`,`Powiedz „w prawo” i „w lewo”.`,`Zapytaj „Gdzie jesteśmy?”.`]},{day: 8, title: `Transport miejski w Tokio`, title_native: `東京の公共交通`, focus: `Nauczysz się słów związanych z metrem, pociągiem i przesiadką. Tokio ma rozbudowaną sieć transportu, więc te zwroty są kluczowe dla podróżnika.`, vocab: [{ja: `地下鉄`, pl: `metro`, ipa: `czi-ka-te-cu`},{ja: `線`, pl: `linia`, ipa: `sen`},{ja: `山手線`, pl: `linia Yamanote`, ipa: `ja-ma-no-te-sen`},{ja: `乗り換え`, pl: `przesiadka`, ipa: `no-ri-ka-e`},{ja: `ホーム`, pl: `peron`, ipa: `ho-o-mu`},{ja: `改札`, pl: `bramki biletowe`, ipa: `ka-i-sa-cu`},{ja: `駅員`, pl: `pracownik stacji`, ipa: `e-ki-in`},{ja: `次`, pl: `następny`, ipa: `cu-gi`},{ja: `終点`, pl: `ostatnia stacja`, ipa: `szuu-ten`},{ja: `遅れ`, pl: `opóźnienie`, ipa: `o-ku-re`}], phrases: [{ja: `地下鉄に乗ります。`, pl: `Wsiadam do metra.`, ipa: `czi-ka-te-cu ni no-ri-mas`},{ja: `山手線はどこですか。`, pl: `Gdzie jest linia Yamanote?`, ipa: `ja-ma-no-te-sen wa do-ko des ka`},{ja: `乗り換えはありますか。`, pl: `Czy jest przesiadka?`, ipa: `no-ri-ka-e wa a-ri-mas ka`},{ja: `次の駅で降ります。`, pl: `Wysiadam na następnej stacji.`, ipa: `cu-gi no e-ki de o-ri-mas`},{ja: `ホームはどこですか。`, pl: `Gdzie jest peron?`, ipa: `ho-o-mu wa do-ko des ka`},{ja: `遅れていますか。`, pl: `Czy jest opóźnienie?`, ipa: `o-ku-re-te i-mas ka`}], grammar: `Czasowniki ruchu często łączą się z partykułami に i で. に może oznaczać kierunek lub punkt docelowy, a で miejsce wykonania czynności. 乗ります znaczy „wsiadam/jadę”, a 降ります znaczy „wysiadam”. W transporcie warto zapamiętać całe frazy, bo pojawiają się często na stacjach.`, practice: [`Powiedz, że wsiadasz do metra.`,`Zapytaj, gdzie jest peron.`,`Zapytaj, czy jest przesiadka.`,`Powiedz, że wysiadasz na następnej stacji.`,`Zapytaj, czy jest opóźnienie.`]},{day: 9, title: `Zamawianie kawy w Fukuoce`, title_native: `福岡でコーヒーを注文する`, focus: `Nauczysz się zamawiać napoje i wybierać rozmiar. Przyda się to w kawiarni w Fukuoce, kiedy chcesz szybko i grzecznie złożyć zamówienie.`, vocab: [{ja: `カフェ`, pl: `kawiarnia`, ipa: `ka-fe`},{ja: `メニュー`, pl: `menu`, ipa: `me-njuu`},{ja: `コーヒー`, pl: `kawa`, ipa: `ko-o-hii`},{ja: `紅茶`, pl: `czarna herbata`, ipa: `ko-o-czia`},{ja: `牛乳`, pl: `mleko`, ipa: `gjū-njū`},{ja: `砂糖`, pl: `cukier`, ipa: `sa-to-o`},{ja: `小さい`, pl: `mały`, ipa: `czii-sa-i`},{ja: `大きい`, pl: `duży`, ipa: `oo-ki-i`},{ja: `冷たい`, pl: `zimny`, ipa: `cu-me-ta-i`},{ja: `温かい`, pl: `ciepły`, ipa: `a-ta-ta-ka-i`}], phrases: [{ja: `コーヒーをください。`, pl: `Poproszę kawę.`, ipa: `ko-o-hii o ku-da-sa-i`},{ja: `温かいコーヒーをください。`, pl: `Poproszę ciepłą kawę.`, ipa: `a-ta-ta-ka-i ko-o-hii o ku-da-sa-i`},{ja: `冷たいお茶をください。`, pl: `Poproszę zimną herbatę.`, ipa: `cu-me-ta-i o-czia o ku-da-sa-i`},{ja: `砂糖はいりません。`, pl: `Nie potrzebuję cukru.`, ipa: `sa-to-o wa i-ri-ma-sen`},{ja: `牛乳をお願いします。`, pl: `Poproszę mleko.`, ipa: `gjū-njū o o-ne-ga-i szi-mas`},{ja: `小さいサイズでお願いします。`, pl: `Poproszę mały rozmiar.`, ipa: `czii-sa-i sa-i-zu de o-ne-ga-i szi-mas`}], grammar: `いりません znaczy „nie potrzebuję” i jest uprzejmą odmową. Przymiotnik przed rzeczownikiem stoi bez dodatkowych zmian, na przykład 冷たいお茶. Forma でお願いします jest bardzo praktyczna przy wyborze opcji: „w tej wersji poproszę”. W kawiarni możesz używać jej z rozmiarem, temperaturą albo sposobem podania.`, practice: [`Zamów ciepłą kawę.`,`Zamów zimną herbatę.`,`Powiedz, że nie potrzebujesz cukru.`,`Poproś o mleko.`,`Poproś o mały rozmiar.`]},{day: 10, title: `Jedzenie uliczne w Osace`, title_native: `大阪の屋台料理`, focus: `Nauczysz się zamawiać popularne jedzenie i mówić, czy coś lubisz. W Osace, znanej z takoyaki i okonomiyaki, jedzenie uliczne jest częścią podróży.`, vocab: [{ja: `食べ物`, pl: `jedzenie`, ipa: `ta-be-mo-no`},{ja: `たこ焼き`, pl: `takoyaki`, ipa: `ta-ko-ja-ki`},{ja: `お好み焼き`, pl: `okonomiyaki`, ipa: `o-ko-no-mi-ja-ki`},{ja: `ラーメン`, pl: `ramen`, ipa: `ra-a-men`},{ja: `寿司`, pl: `sushi`, ipa: `su-szi`},{ja: `おいしい`, pl: `smaczne`, ipa: `o-i-szii`},{ja: `好き`, pl: `lubiany / lubię`, ipa: `su-ki`},{ja: `辛い`, pl: `ostre`, ipa: `ka-ra-i`},{ja: `甘い`, pl: `słodkie`, ipa: `a-ma-i`},{ja: `熱い`, pl: `gorące`, ipa: `a-cu-i`}], phrases: [{ja: `たこ焼きをください。`, pl: `Poproszę takoyaki.`, ipa: `ta-ko-ja-ki o ku-da-sa-i`},{ja: `これはおいしいです。`, pl: `To jest smaczne.`, ipa: `ko-re wa o-i-szii des`},{ja: `辛いですか。`, pl: `Czy to jest ostre?`, ipa: `ka-ra-i des ka`},{ja: `ラーメンが好きです。`, pl: `Lubię ramen.`, ipa: `ra-a-men ga su-ki des`},{ja: `寿司は好きですか。`, pl: `Czy lubisz sushi?`, ipa: `su-szi wa su-ki des ka`},{ja: `熱いです。`, pl: `To jest gorące.`, ipa: `a-cu-i des`}], grammar: `好き zachowuje się jak przymiotnik, mimo że po polsku tłumaczymy go czasownikiem „lubić”. Mówimy ラーメンが好きです, dosłownie „ramen jest lubiany”. Partykuła が często wskazuje rzecz, która jest przedmiotem odczucia. W restauracji pytanie 辛いですか pomaga uniknąć zbyt ostrego jedzenia.`, practice: [`Powiedz, że lubisz ramen.`,`Zapytaj, czy coś jest ostre.`,`Powiedz, że jedzenie jest smaczne.`,`Zamów takoyaki.`,`Zapytaj kogoś, czy lubi sushi.`]},{day: 11, title: `W restauracji w Hiroszimie`, title_native: `広島のレストランで`, focus: `Nauczysz się prosić o stolik, menu i rachunek. W Hiroszimie przyda się to, gdy wejdziesz do małej restauracji z lokalnymi daniami.`, vocab: [{ja: `レストラン`, pl: `restauracja`, ipa: `re-su-to-ran`},{ja: `席`, pl: `miejsce / stolik`, ipa: `se-ki`},{ja: `一人`, pl: `jedna osoba`, ipa: `hi-to-ri`},{ja: `二人`, pl: `dwie osoby`, ipa: `fu-ta-ri`},{ja: `メニュー`, pl: `menu`, ipa: `me-njuu`},{ja: `おすすめ`, pl: `rekomendacja`, ipa: `o-su-su-me`},{ja: `水`, pl: `woda`, ipa: `mi-zu`},{ja: `注文`, pl: `zamówienie`, ipa: `cziu-mon`},{ja: `会計`, pl: `rachunek`, ipa: `ka-i-ke-e`},{ja: `カード`, pl: `karta`, ipa: `ka-a-do`}], phrases: [{ja: `二人です。`, pl: `Dwie osoby.`, ipa: `fu-ta-ri des`},{ja: `席はありますか。`, pl: `Czy są wolne miejsca?`, ipa: `se-ki wa a-ri-mas ka`},{ja: `メニューをください。`, pl: `Poproszę menu.`, ipa: `me-njuu o ku-da-sa-i`},{ja: `おすすめは何ですか。`, pl: `Co pan/pani poleca?`, ipa: `o-su-su-me wa nan des ka`},{ja: `注文をお願いします。`, pl: `Chciałbym/chciałabym złożyć zamówienie.`, ipa: `cziu-mon o o-ne-ga-i szi-mas`},{ja: `会計をお願いします。`, pl: `Poproszę rachunek.`, ipa: `ka-i-ke-e o o-ne-ga-i szi-mas`}], grammar: `一人 i 二人 mają nieregularną wymowę: ひとり i ふたり. W restauracji często wystarczy powiedzieć 二人です przy wejściu. ありますか pyta, czy coś istnieje lub jest dostępne. Zwrot おすすめは何ですか brzmi naturalnie, gdy chcesz poznać polecane danie.`, practice: [`Powiedz, że jesteście dwie osoby.`,`Poproś o menu.`,`Zapytaj, czy są wolne miejsca.`,`Zapytaj o rekomendację.`,`Poproś o rachunek.`]},{day: 12, title: `Hotel i zameldowanie w Kanazawie`, title_native: `金沢のホテルでチェックイン`, focus: `Nauczysz się słów potrzebnych przy zameldowaniu w hotelu. W Kanazawie, po dniu zwiedzania ogrodów i dzielnicy samurajskiej, te zwroty pomogą ci spokojnie odebrać klucz.`, vocab: [{ja: `ホテル`, pl: `hotel`, ipa: `ho-te-ru`},{ja: `予約`, pl: `rezerwacja`, ipa: `jo-ja-ku`},{ja: `名前`, pl: `nazwisko / imię`, ipa: `na-ma-e`},{ja: `パスポート`, pl: `paszport`, ipa: `pa-su-po-o-to`},{ja: `部屋`, pl: `pokój`, ipa: `he-ja`},{ja: `鍵`, pl: `klucz`, ipa: `ka-gi`},{ja: `チェックイン`, pl: `zameldowanie`, ipa: `czek-ku-in`},{ja: `チェックアウト`, pl: `wymeldowanie`, ipa: `czek-ku-a-u-to`},{ja: `荷物`, pl: `bagaż`, ipa: `ni-mo-cu`},{ja: `朝食`, pl: `śniadanie`, ipa: `czo-o-szo-ku`}], phrases: [{ja: `予約があります。`, pl: `Mam rezerwację.`, ipa: `jo-ja-ku ga a-ri-mas`},{ja: `チェックインをお願いします。`, pl: `Poproszę o zameldowanie.`, ipa: `czek-ku-in o o-ne-ga-i szi-mas`},{ja: `名前はコヴァルスキです。`, pl: `Nazwisko to Kowalski.`, ipa: `na-ma-e wa ko-varu-ski des`},{ja: `パスポートです。`, pl: `Oto paszport.`, ipa: `pa-su-po-o-to des`},{ja: `朝食はありますか。`, pl: `Czy jest śniadanie?`, ipa: `czo-o-szo-ku wa a-ri-mas ka`},{ja: `荷物を預けたいです。`, pl: `Chcę zostawić bagaż.`, ipa: `ni-mo-cu o a-zu-ke-ta-i des`}], grammar: `たいです służy do mówienia „chcę coś zrobić”. W zdaniu 荷物を預けたいです czasownik 預ける oznacza „zostawić/przechować”, a たい dodaje chęć. To uprzejma i praktyczna forma dla podróżnika. があります oznacza „jest/mam” w zależności od kontekstu.`, practice: [`Powiedz, że masz rezerwację.`,`Poproś o zameldowanie.`,`Podaj nazwisko w prostym zdaniu.`,`Zapytaj, czy jest śniadanie.`,`Powiedz, że chcesz zostawić bagaż.`]},{day: 13, title: `Problemy w pokoju hotelowym`, title_native: `ホテルの部屋の問題`, focus: `Nauczysz się zgłaszać proste problemy w hotelu. Przyda się to, jeśli klimatyzacja nie działa albo potrzebujesz nowego ręcznika.`, vocab: [{ja: `問題`, pl: `problem`, ipa: `mon-da-i`},{ja: `エアコン`, pl: `klimatyzacja`, ipa: `e-a-kon`},{ja: `使えます`, pl: `można używać / działa`, ipa: `cu-ka-e-mas`},{ja: `使えません`, pl: `nie można używać / nie działa`, ipa: `cu-ka-e-ma-sen`},{ja: `タオル`, pl: `ręcznik`, ipa: `ta-o-ru`},{ja: `トイレ`, pl: `toaleta`, ipa: `to-i-re`},{ja: `シャワー`, pl: `prysznic`, ipa: `sza-wa-a`},{ja: `寒い`, pl: `zimno`, ipa: `sa-mu-i`},{ja: `暑い`, pl: `gorąco`, ipa: `a-cu-i`},{ja: `助け`, pl: `pomoc`, ipa: `ta-su-ke`}], phrases: [{ja: `エアコンが使えません。`, pl: `Klimatyzacja nie działa.`, ipa: `e-a-kon ga cu-ka-e-ma-sen`},{ja: `タオルをください。`, pl: `Poproszę ręcznik.`, ipa: `ta-o-ru o ku-da-sa-i`},{ja: `シャワーに問題があります。`, pl: `Jest problem z prysznicem.`, ipa: `sza-wa-a ni mon-da-i ga a-ri-mas`},{ja: `部屋が寒いです。`, pl: `W pokoju jest zimno.`, ipa: `he-ja ga sa-mu-i des`},{ja: `部屋が暑いです。`, pl: `W pokoju jest gorąco.`, ipa: `he-ja ga a-cu-i des`},{ja: `助けてください。`, pl: `Proszę pomóc.`, ipa: `ta-su-ke-te ku-da-sa-i`}], grammar: `使えません oznacza „nie da się używać” i jest bardzo przydatne przy zgłaszaniu awarii. Partykuła が wskazuje rzecz, z którą dzieje się problem. に問題があります znaczy „jest problem z…”. W sytuacji pilnej 助けてください jest prostym, zrozumiałym wezwaniem pomocy.`, practice: [`Powiedz, że klimatyzacja nie działa.`,`Poproś o ręcznik.`,`Powiedz, że w pokoju jest zimno.`,`Zgłoś problem z prysznicem.`,`Powiedz „Proszę pomóc”.`]},{day: 14, title: `Zakupy i pamiątki w Kioto`, title_native: `京都でのお土産`, focus: `Nauczysz się kupować pamiątki i pytać o ceny, rozmiar oraz kolor. W Kioto przyda się to w sklepach z wachlarzami, ceramiką i słodyczami matcha.`, vocab: [{ja: `お土産`, pl: `pamiątka`, ipa: `o-mi-ja-ge`},{ja: `店`, pl: `sklep`, ipa: `mi-se`},{ja: `値段`, pl: `cena`, ipa: `ne-dan`},{ja: `安い`, pl: `tani`, ipa: `ja-su-i`},{ja: `高い`, pl: `drogi`, ipa: `ta-ka-i`},{ja: `色`, pl: `kolor`, ipa: `i-ro`},{ja: `赤`, pl: `czerwony`, ipa: `a-ka`},{ja: `青`, pl: `niebieski`, ipa: `a-o`},{ja: `白`, pl: `biały`, ipa: `szi-ro`},{ja: `黒`, pl: `czarny`, ipa: `ku-ro`}], phrases: [{ja: `お土産を買いたいです。`, pl: `Chcę kupić pamiątkę.`, ipa: `o-mi-ja-ge o ka-i-ta-i des`},{ja: `これはいくらですか。`, pl: `Ile to kosztuje?`, ipa: `ko-re wa i-ku-ra des ka`},{ja: `安いですね。`, pl: `To tanie, prawda?`, ipa: `ja-su-i des ne`},{ja: `赤いものはありますか。`, pl: `Czy jest coś czerwonego?`, ipa: `a-ka-i mo-no wa a-ri-mas ka`},{ja: `これを見てもいいですか。`, pl: `Czy mogę to obejrzeć?`, ipa: `ko-re o mi-te mo ii des ka`},{ja: `カードで払えますか。`, pl: `Czy mogę zapłacić kartą?`, ipa: `ka-a-do de ha-ra-e-mas ka`}], grammar: `たいです wyraża chęć: 買いたいです znaczy „chcę kupić”. てもいいですか pyta o pozwolenie, na przykład 見てもいいですか — „czy mogę zobaczyć?”. Kolory takie jak 赤 mogą przyjmować formę przymiotnikową 赤い. W sklepach ですね brzmi jak łagodne potwierdzenie lub komentarz.`, practice: [`Powiedz, że chcesz kupić pamiątkę.`,`Zapytaj o cenę przedmiotu.`,`Zapytaj, czy możesz obejrzeć przedmiot.`,`Zapytaj, czy można płacić kartą.`,`Poproś o coś czerwonego.`]},{day: 15, title: `Ubrania i rozmiary w Harajuku`, title_native: `原宿での服とサイズ`, focus: `Nauczysz się pytać o ubrania, rozmiary i przymierzalnię. Harajuku w Tokio to dobre miejsce na praktykę zakupów modowych.`, vocab: [{ja: `服`, pl: `ubrania`, ipa: `fu-ku`},{ja: `シャツ`, pl: `koszula / T-shirt`, ipa: `sza-cu`},{ja: `ズボン`, pl: `spodnie`, ipa: `zu-bon`},{ja: `靴`, pl: `buty`, ipa: `ku-cu`},{ja: `サイズ`, pl: `rozmiar`, ipa: `sa-i-zu`},{ja: `小さい`, pl: `mały`, ipa: `czii-sa-i`},{ja: `大きい`, pl: `duży`, ipa: `oo-ki-i`},{ja: `試着室`, pl: `przymierzalnia`, ipa: `szi-czaku-szicu`},{ja: `似合います`, pl: `pasuje / dobrze wygląda`, ipa: `ni-a-i-mas`},{ja: `買います`, pl: `kupuję`, ipa: `ka-i-mas`}], phrases: [{ja: `このシャツを見たいです。`, pl: `Chcę zobaczyć tę koszulę.`, ipa: `ko-no sza-cu o mi-ta-i des`},{ja: `大きいサイズはありますか。`, pl: `Czy jest większy rozmiar?`, ipa: `oo-ki-i sa-i-zu wa a-ri-mas ka`},{ja: `小さいサイズはありますか。`, pl: `Czy jest mniejszy rozmiar?`, ipa: `czii-sa-i sa-i-zu wa a-ri-mas ka`},{ja: `試着してもいいですか。`, pl: `Czy mogę przymierzyć?`, ipa: `szi-czaku szi-te mo ii des ka`},{ja: `似合いますか。`, pl: `Czy dobrze wygląda?`, ipa: `ni-a-i-mas ka`},{ja: `これを買います。`, pl: `Kupię to.`, ipa: `ko-re o ka-i-mas`}], grammar: `この oznacza „ten/ta/to” i stoi przed rzeczownikiem, na przykład このシャツ. Różni się od これ, które samo znaczy „to”. Forma してもいいですか pyta o pozwolenie na wykonanie czynności. 試着してもいいですか to naturalny zwrot w sklepie z ubraniami.`, practice: [`Zapytaj o większy rozmiar.`,`Zapytaj o mniejszy rozmiar.`,`Powiedz, że chcesz zobaczyć tę koszulę.`,`Zapytaj, czy możesz przymierzyć.`,`Powiedz „Kupię to”.`]},{day: 16, title: `Pogoda i plany w Okinawie`, title_native: `沖縄の天気と予定`, focus: `Nauczysz się mówić o pogodzie i prostych planach. Na Okinawie pogoda może zmienić plażowy dzień w dzień muzealny, więc warto znać te zwroty.`, vocab: [{ja: `天気`, pl: `pogoda`, ipa: `ten-ki`},{ja: `晴れ`, pl: `słonecznie`, ipa: `ha-re`},{ja: `雨`, pl: `deszcz`, ipa: `a-me`},{ja: `風`, pl: `wiatr`, ipa: `ka-ze`},{ja: `暑い`, pl: `gorąco`, ipa: `a-cu-i`},{ja: `寒い`, pl: `zimno`, ipa: `sa-mu-i`},{ja: `海`, pl: `morze`, ipa: `u-mi`},{ja: `ビーチ`, pl: `plaża`, ipa: `bii-czi`},{ja: `傘`, pl: `parasol`, ipa: `ka-sa`},{ja: `予定`, pl: `plan`, ipa: `jo-te-e`}], phrases: [{ja: `今日は暑いです。`, pl: `Dziś jest gorąco.`, ipa: `kjo-o wa a-cu-i des`},{ja: `雨が降っています。`, pl: `Pada deszcz.`, ipa: `a-me ga fut-te i-mas`},{ja: `傘が必要です。`, pl: `Potrzebny jest parasol.`, ipa: `ka-sa ga hi-cu-jo-o des`},{ja: `海に行きたいです。`, pl: `Chcę iść nad morze.`, ipa: `u-mi ni i-ki-ta-i des`},{ja: `予定を変えます。`, pl: `Zmieniam plan.`, ipa: `jo-te-e o ka-e-mas`},{ja: `明日は晴れですか。`, pl: `Czy jutro będzie słonecznie?`, ipa: `a-si-ta wa ha-re des ka`}], grammar: `ています opisuje trwającą czynność lub stan, na przykład 雨が降っています — „pada deszcz”. 必要です oznacza „jest potrzebne”. W zdaniu 海に行きたいです partykuła に wskazuje cel ruchu. To dobry wzór do mówienia o miejscach, do których chcesz iść.`, practice: [`Powiedz, że dziś jest gorąco.`,`Powiedz, że pada deszcz.`,`Zapytaj, czy jutro będzie słonecznie.`,`Powiedz, że chcesz iść nad morze.`,`Powiedz, że zmieniasz plan.`]},{day: 17, title: `Zdrowie i apteka w Nagoi`, title_native: `名古屋の薬局で`, focus: `Nauczysz się opisywać podstawowe dolegliwości i prosić o lekarstwo. W aptece w Nagoi te zdania pomogą ci szybko wyjaśnić problem.`, vocab: [{ja: `薬局`, pl: `apteka`, ipa: `jaku-kjoku`},{ja: `薬`, pl: `lekarstwo`, ipa: `kusuri`},{ja: `頭`, pl: `głowa`, ipa: `atama`},{ja: `お腹`, pl: `brzuch`, ipa: `o-naka`},{ja: `喉`, pl: `gardło`, ipa: `nodo`},{ja: `痛い`, pl: `boli`, ipa: `i-ta-i`},{ja: `熱`, pl: `gorączka`, ipa: `ne-cu`},{ja: `風邪`, pl: `przeziębienie`, ipa: `ka-ze`},{ja: `アレルギー`, pl: `alergia`, ipa: `a-rerugii`},{ja: `医者`, pl: `lekarz`, ipa: `i-sza`}], phrases: [{ja: `頭が痛いです。`, pl: `Boli mnie głowa.`, ipa: `atama ga i-ta-i des`},{ja: `お腹が痛いです。`, pl: `Boli mnie brzuch.`, ipa: `o-naka ga i-ta-i des`},{ja: `喉が痛いです。`, pl: `Boli mnie gardło.`, ipa: `nodo ga i-ta-i des`},{ja: `熱があります。`, pl: `Mam gorączkę.`, ipa: `ne-cu ga a-ri-mas`},{ja: `薬をください。`, pl: `Poproszę lekarstwo.`, ipa: `kusuri o ku-da-sa-i`},{ja: `医者に行きたいです。`, pl: `Chcę iść do lekarza.`, ipa: `i-sza ni i-ki-ta-i des`}], grammar: `W japońskim dolegliwości często opisuje się schematem część ciała + が痛いです. Dosłownie: „głowa jest bolesna”. 熱があります oznacza „jest gorączka”, czyli po polsku „mam gorączkę”. W aptece warto mówić krótko i jasno.`, practice: [`Powiedz, że boli cię głowa.`,`Powiedz, że boli cię brzuch.`,`Powiedz, że masz gorączkę.`,`Poproś o lekarstwo.`,`Powiedz, że chcesz iść do lekarza.`]},{day: 18, title: `Bezpieczeństwo i pomoc w Kobe`, title_native: `神戸での安全と助け`, focus: `Nauczysz się prosić o pomoc i zgłaszać nagłe sytuacje. To ważne w każdym mieście, również podczas nocnego spaceru po Kobe.`, vocab: [{ja: `助けて`, pl: `pomocy`, ipa: `ta-su-ke-te`},{ja: `警察`, pl: `policja`, ipa: `ke-e-sa-cu`},{ja: `病院`, pl: `szpital`, ipa: `bjo-o-in`},{ja: `危ない`, pl: `niebezpieczne`, ipa: `a-bu-na-i`},{ja: `財布`, pl: `portfel`, ipa: `sa-i-fu`},{ja: `携帯`, pl: `telefon komórkowy`, ipa: `ke-e-ta-i`},{ja: `なくしました`, pl: `zgubiłem/zgubiłam`, ipa: `na-ku-szi-ma-szi-ta`},{ja: `盗まれました`, pl: `skradziono`, ipa: `nu-su-ma-re-ma-szi-ta`},{ja: `事故`, pl: `wypadek`, ipa: `dźi-ko`},{ja: `大丈夫`, pl: `w porządku`, ipa: `da-i-dzio-o-bu`}], phrases: [{ja: `助けてください。`, pl: `Proszę pomóc.`, ipa: `ta-su-ke-te ku-da-sa-i`},{ja: `警察を呼んでください。`, pl: `Proszę wezwać policję.`, ipa: `ke-e-sa-cu o jon-de ku-da-sa-i`},{ja: `病院はどこですか。`, pl: `Gdzie jest szpital?`, ipa: `bjo-o-in wa do-ko des ka`},{ja: `財布をなくしました。`, pl: `Zgubiłem/zgubiłam portfel.`, ipa: `sa-i-fu o na-ku-szi-ma-szi-ta`},{ja: `携帯を盗まれました。`, pl: `Skradziono mi telefon.`, ipa: `ke-e-ta-i o nu-su-ma-re-ma-szi-ta`},{ja: `大丈夫です。`, pl: `Wszystko w porządku.`, ipa: `da-i-dzio-o-bu des`}], grammar: `Forma てください oznacza „proszę zrobić”. 呼んでください znaczy „proszę wezwać/zawołać”. なくしました to forma przeszła od „zgubić”, a 盗まれました to forma bierna: „zostało skradzione”. W sytuacji stresowej nie musisz mówić perfekcyjnie — najważniejsze są słowa kluczowe.`, practice: [`Poproś o pomoc.`,`Poproś o wezwanie policji.`,`Powiedz, że zgubiłeś portfel.`,`Powiedz, że skradziono ci telefon.`,`Zapytaj, gdzie jest szpital.`]},{day: 19, title: `Rozmowy telefoniczne i internet`, title_native: `電話とインターネット`, focus: `Nauczysz się pytać o Wi-Fi, kartę SIM i problemy z połączeniem. W Japonii internet jest przydatny do map, tłumaczeń i biletów.`, vocab: [{ja: `電話`, pl: `telefon`, ipa: `den-wa`},{ja: `インターネット`, pl: `internet`, ipa: `in-ta-a-net-to`},{ja: `Wi-Fi`, pl: `Wi-Fi`, ipa: `wa-i-fa-i`},{ja: `パスワード`, pl: `hasło`, ipa: `pa-su-wa-a-do`},{ja: `SIMカード`, pl: `karta SIM`, ipa: `sim ka-a-do`},{ja: `充電`, pl: `ładowanie`, ipa: `dźiuu-den`},{ja: `電池`, pl: `bateria`, ipa: `den-czi`},{ja: `使えます`, pl: `działa / można użyć`, ipa: `cu-ka-e-mas`},{ja: `遅い`, pl: `wolny / powolny`, ipa: `o-so-i`},{ja: `必要`, pl: `potrzebny`, ipa: `hi-cu-jo-o`}], phrases: [{ja: `Wi-Fiはありますか。`, pl: `Czy jest Wi-Fi?`, ipa: `wa-i-fa-i wa a-ri-mas ka`},{ja: `パスワードは何ですか。`, pl: `Jakie jest hasło?`, ipa: `pa-su-wa-a-do wa nan des ka`},{ja: `SIMカードを買いたいです。`, pl: `Chcę kupić kartę SIM.`, ipa: `sim ka-a-do o ka-i-ta-i des`},{ja: `充電できますか。`, pl: `Czy mogę naładować?`, ipa: `dźiuu-den de-ki-mas ka`},{ja: `インターネットが遅いです。`, pl: `Internet jest wolny.`, ipa: `in-ta-a-net-to ga o-so-i des`},{ja: `電話を使えますか。`, pl: `Czy mogę użyć telefonu?`, ipa: `den-wa o cu-ka-e-mas ka`}], grammar: `できます oznacza „mogę / da się”. To bardzo praktyczne przy pytaniu o możliwość: 充電できますか. 使えます ma podobne znaczenie, ale bardziej skupia się na używaniu czegoś. W wielu miejscach pytanie Wi-Fiはありますか wystarczy, aby otrzymać informację o sieci.`, practice: [`Zapytaj, czy jest Wi-Fi.`,`Zapytaj o hasło.`,`Powiedz, że chcesz kupić kartę SIM.`,`Zapytaj, czy możesz naładować telefon.`,`Powiedz, że internet jest wolny.`]},{day: 20, title: `Zwiedzanie świątyń w Kioto`, title_native: `京都のお寺を観光する`, focus: `Nauczysz się słów i zwrotów przydatnych w miejscach kultury. W Kioto, podczas wizyty w świątyniach i ogrodach, ważna jest uprzejmość i cisza.`, vocab: [{ja: `寺`, pl: `świątynia buddyjska`, ipa: `te-ra`},{ja: `神社`, pl: `świątynia shintō`, ipa: `dźin-dzia`},{ja: `庭`, pl: `ogród`, ipa: `ni-wa`},{ja: `写真`, pl: `zdjęcie`, ipa: `sza-szin`},{ja: `入場料`, pl: `opłata za wejście`, ipa: `njū-dzio-o-rjo-o`},{ja: `静か`, pl: `cicho / spokojnie`, ipa: `szu-zu-ka`},{ja: `きれい`, pl: `piękne / czyste`, ipa: `ki-re-e`},{ja: `古い`, pl: `stare`, ipa: `fu-ru-i`},{ja: `歴史`, pl: `historia`, ipa: `re-ki-szi`},{ja: `観光`, pl: `zwiedzanie`, ipa: `kan-ko-o`}], phrases: [{ja: `写真を撮ってもいいですか。`, pl: `Czy mogę zrobić zdjęcie?`, ipa: `sza-szin o tot-te mo ii des ka`},{ja: `入場料はいくらですか。`, pl: `Ile kosztuje wejście?`, ipa: `njū-dzio-o-rjo-o wa i-ku-ra des ka`},{ja: `この庭はきれいです。`, pl: `Ten ogród jest piękny.`, ipa: `ko-no ni-wa wa ki-re-e des`},{ja: `静かにしてください。`, pl: `Proszę zachować ciszę.`, ipa: `szu-zu-ka ni szi-te ku-da-sa-i`},{ja: `歴史があります。`, pl: `To ma historię.`, ipa: `re-ki-szi ga a-ri-mas`},{ja: `寺に行きます。`, pl: `Idę do świątyni.`, ipa: `te-ra ni i-ki-mas`}], grammar: `てもいいですか pyta o pozwolenie, a w miejscach kultury jest szczególnie przydatne. 撮る znaczy „robić zdjęcie”, a 撮ってもいいですか oznacza „czy można zrobić zdjęcie?”. Przymiotnik きれい jest przymiotnikiem typu な, ale w prostym zdaniu mówimy po prostu きれいです.`, practice: [`Zapytaj, czy możesz zrobić zdjęcie.`,`Zapytaj o opłatę za wejście.`,`Powiedz, że ogród jest piękny.`,`Powiedz, że idziesz do świątyni.`,`Zrozum polecenie „Proszę zachować ciszę”.`]},{day: 21, title: `Wycieczki i rezerwacje w Hakone`, title_native: `箱根でのツアーと予約`, focus: `Nauczysz się pytać o wycieczki, bilety i dostępność. W Hakone przyda się to przy planowaniu rejsu po jeziorze, kolejki linowej lub wizyty w onsenie.`, vocab: [{ja: `ツアー`, pl: `wycieczka`, ipa: `cua-a`},{ja: `予約`, pl: `rezerwacja`, ipa: `jo-ja-ku`},{ja: `空き`, pl: `wolne miejsce`, ipa: `a-ki`},{ja: `チケット`, pl: `bilet`, ipa: `czik-ket-to`},{ja: `船`, pl: `statek`, ipa: `fu-ne`},{ja: `ロープウェイ`, pl: `kolejka linowa`, ipa: `ro-o-pu-we-i`},{ja: `温泉`, pl: `gorące źródła / onsen`, ipa: `on-sen`},{ja: `大人`, pl: `dorosły`, ipa: `o-to-na`},{ja: `子ども`, pl: `dziecko`, ipa: `ko-do-mo`},{ja: `出発`, pl: `odjazd / wyjazd`, ipa: `szup-pa-cu`}], phrases: [{ja: `ツアーを予約したいです。`, pl: `Chcę zarezerwować wycieczkę.`, ipa: `cua-a o jo-ja-ku szi-ta-i des`},{ja: `空きはありますか。`, pl: `Czy są wolne miejsca?`, ipa: `a-ki wa a-ri-mas ka`},{ja: `チケットを二枚ください。`, pl: `Poproszę dwa bilety.`, ipa: `czik-ket-to o ni-ma-i ku-da-sa-i`},{ja: `出発は何時ですか。`, pl: `O której jest odjazd?`, ipa: `szup-pa-cu wa nan-dźi des ka`},{ja: `温泉に行きたいです。`, pl: `Chcę iść do onsenu.`, ipa: `on-sen ni i-ki-ta-i des`},{ja: `大人一人です。`, pl: `Jeden dorosły.`, ipa: `o-to-na hi-to-ri des`}], grammar: `枚 to liczebnik używany między innymi do płaskich przedmiotów, takich jak bilety. 二枚 znaczy „dwie sztuki” w tym kontekście. 予約したいです to „chcę zarezerwować”, a ありますか pyta o dostępność. W turystyce te trzy wzory pojawiają się bardzo często.`, practice: [`Powiedz, że chcesz zarezerwować wycieczkę.`,`Zapytaj, czy są wolne miejsca.`,`Poproś o dwa bilety.`,`Zapytaj, o której jest odjazd.`,`Powiedz, że chcesz iść do onsenu.`]},{day: 22, title: `Na dworcu Shinkansen`, title_native: `新幹線の駅で`, focus: `Nauczysz się słów związanych z szybkim pociągiem Shinkansen. Przyda się to podczas podróży z Tokio do Kioto, Osaki lub Hiroszimy.`, vocab: [{ja: `新幹線`, pl: `Shinkansen`, ipa: `szin-kan-sen`},{ja: `指定席`, pl: `miejsce rezerwowane`, ipa: `szi-te-e-se-ki`},{ja: `自由席`, pl: `miejsce nierezerwowane`, ipa: `dźi-jū-se-ki`},{ja: `片道`, pl: `w jedną stronę`, ipa: `ka-ta-mi-czi`},{ja: `往復`, pl: `w obie strony`, ipa: `o-o-fu-ku`},{ja: `窓側`, pl: `przy oknie`, ipa: `ma-do-ga-wa`},{ja: `通路側`, pl: `od strony przejścia`, ipa: `cuu-ro-ga-wa`},{ja: `乗車券`, pl: `bilet przejazdowy`, ipa: `dźio-o-sza-ken`},{ja: `特急券`, pl: `bilet ekspresowy`, ipa: `tok-kyuu-ken`},{ja: `到着`, pl: `przyjazd`, ipa: `to-o-czaku`}], phrases: [{ja: `新幹線の切符をください。`, pl: `Poproszę bilet na Shinkansen.`, ipa: `szin-kan-sen no kip-pu o ku-da-sa-i`},{ja: `京都まで片道です。`, pl: `W jedną stronę do Kioto.`, ipa: `kjo-o-to ma-de ka-ta-mi-czi des`},{ja: `指定席をお願いします。`, pl: `Poproszę miejsce rezerwowane.`, ipa: `szi-te-e-se-ki o o-ne-ga-i szi-mas`},{ja: `窓側はありますか。`, pl: `Czy jest miejsce przy oknie?`, ipa: `ma-do-ga-wa wa a-ri-mas ka`},{ja: `到着は何時ですか。`, pl: `O której jest przyjazd?`, ipa: `to-o-czaku wa nan-dźi des ka`},{ja: `自由席でもいいです。`, pl: `Miejsce nierezerwowane też jest w porządku.`, ipa: `dźi-jū-se-ki de-mo ii des`}], grammar: `まで oznacza „do” jako punkt docelowy: 京都まで. の łączy rzeczowniki, więc 新幹線の切符 to „bilet Shinkansen”. でもいいです znaczy „też jest w porządku” i przydaje się, gdy jesteś elastyczny. W kasie biletowej krótkie rzeczowniki z です brzmią naturalnie.`, practice: [`Poproś o bilet na Shinkansen.`,`Powiedz „w jedną stronę do Kioto”.`,`Poproś o miejsce rezerwowane.`,`Zapytaj o miejsce przy oknie.`,`Zapytaj, o której jest przyjazd.`]},{day: 23, title: `Taksówka i adresy w Tokio`, title_native: `東京でタクシーに乗る`, focus: `Nauczysz się podawać kierunek taksówkarzowi i mówić o adresie. W Tokio, szczególnie wieczorem, taksówka bywa najwygodniejszym rozwiązaniem.`, vocab: [{ja: `タクシー`, pl: `taksówka`, ipa: `ta-ku-szii`},{ja: `住所`, pl: `adres`, ipa: `dźiuu-szio`},{ja: `ホテル`, pl: `hotel`, ipa: `ho-te-ru`},{ja: `空港`, pl: `lotnisko`, ipa: `kuu-ko-o`},{ja: `ここ`, pl: `tutaj`, ipa: `ko-ko`},{ja: `そこ`, pl: `tam blisko rozmówcy`, ipa: `so-ko`},{ja: `まっすぐ`, pl: `prosto`, ipa: `mas-su-gu`},{ja: `止めて`, pl: `zatrzymaj`, ipa: `to-me-te`},{ja: `急いで`, pl: `szybko / proszę się spieszyć`, ipa: `i-so-i-de`},{ja: `料金`, pl: `opłata`, ipa: `rjo-o-kin`}], phrases: [{ja: `この住所までお願いします。`, pl: `Pod ten adres poproszę.`, ipa: `ko-no dźiuu-szio ma-de o-ne-ga-i szi-mas`},{ja: `ホテルまでお願いします。`, pl: `Do hotelu poproszę.`, ipa: `ho-te-ru ma-de o-ne-ga-i szi-mas`},{ja: `空港まで行ってください。`, pl: `Proszę jechać na lotnisko.`, ipa: `kuu-ko-o ma-de it-te ku-da-sa-i`},{ja: `ここで止めてください。`, pl: `Proszę zatrzymać tutaj.`, ipa: `ko-ko de to-me-te ku-da-sa-i`},{ja: `まっすぐ行ってください。`, pl: `Proszę jechać prosto.`, ipa: `mas-su-gu it-te ku-da-sa-i`},{ja: `料金はいくらですか。`, pl: `Ile wynosi opłata?`, ipa: `rjo-o-kin wa i-ku-ra des ka`}], grammar: `まで wskazuje cel podróży: ホテルまで. お願いします po celu brzmi naturalnie i uprzejmie w taksówce. ここで oznacza „tutaj jako miejsce wykonania czynności”, dlatego ここで止めてください znaczy „proszę zatrzymać tutaj”. Czasownik 行く może znaczyć „iść” lub „jechać” w zależności od kontekstu.`, practice: [`Powiedz „Do hotelu poproszę”.`,`Powiedz „Pod ten adres poproszę”.`,`Poproś o zatrzymanie tutaj.`,`Zapytaj o opłatę.`,`Poproś, aby kierowca jechał prosto.`]},{day: 24, title: `Mała rozmowa z lokalną osobą`, title_native: `地元の人との会話`, focus: `Nauczysz się prostych zwrotów do small talku. W kawiarni, pociągu lub hostelu możesz dzięki nim krótko porozmawiać z mieszkańcem Japonii.`, vocab: [{ja: `どちら`, pl: `skąd / gdzie, grzecznie`, ipa: `do-czi-ra`},{ja: `出身`, pl: `pochodzenie`, ipa: `szusz-szin`},{ja: `仕事`, pl: `praca`, ipa: `szi-go-to`},{ja: `趣味`, pl: `hobby`, ipa: `sziu-mi`},{ja: `音楽`, pl: `muzyka`, ipa: `on-ga-ku`},{ja: `映画`, pl: `film`, ipa: `e-e-ga`},{ja: `旅行`, pl: `podróż`, ipa: `rjo-ko-o`},{ja: `楽しい`, pl: `przyjemne / fajne`, ipa: `ta-no-szii`},{ja: `忙しい`, pl: `zajęty`, ipa: `i-so-ga-szii`},{ja: `少し`, pl: `trochę`, ipa: `su-ko-szi`}], phrases: [{ja: `どちらの出身ですか。`, pl: `Skąd pan/pani pochodzi?`, ipa: `do-czi-ra no szusz-szin des ka`},{ja: `ポーランド出身です。`, pl: `Pochodzę z Polski.`, ipa: `po-o-ran-do szusz-szin des`},{ja: `日本は楽しいです。`, pl: `Japonia jest przyjemna.`, ipa: `ni-hon wa ta-no-szii des`},{ja: `趣味は何ですか。`, pl: `Jakie masz hobby?`, ipa: `sziu-mi wa nan des ka`},{ja: `音楽が好きです。`, pl: `Lubię muzykę.`, ipa: `on-ga-ku ga su-ki des`},{ja: `日本語を少し話します。`, pl: `Mówię trochę po japońsku.`, ipa: `ni-hon-go o su-ko-szi ha-na-szi-mas`}], grammar: `出身です to wygodny sposób mówienia, skąd się pochodzi. 日本語 oznacza język japoński, a ポーランド語 oznacza polski. 少し łagodzi wypowiedź i jest przydatne, gdy chcesz powiedzieć „trochę”. W Japonii skromna forma 日本語を少し話します brzmi naturalnie.`, practice: [`Powiedz, że pochodzisz z Polski.`,`Zapytaj kogoś, skąd pochodzi.`,`Powiedz, że lubisz muzykę.`,`Powiedz, że mówisz trochę po japońsku.`,`Zapytaj o hobby.`]},{day: 25, title: `Umawianie spotkania w Shibuyi`, title_native: `渋谷で待ち合わせ`, focus: `Nauczysz się umawiać godzinę i miejsce spotkania. W Shibuyi, przy znanym skrzyżowaniu i pomniku Hachikō, precyzyjne ustalenia są bardzo pomocne.`, vocab: [{ja: `待ち合わせ`, pl: `spotkanie / umówienie się`, ipa: `ma-czi-a-wa-se`},{ja: `会います`, pl: `spotykam się`, ipa: `a-i-mas`},{ja: `場所`, pl: `miejsce`, ipa: `ba-szio`},{ja: `時間`, pl: `czas`, ipa: `dźi-kan`},{ja: `午後`, pl: `po południu`, ipa: `go-go`},{ja: `午前`, pl: `przed południem`, ipa: `go-zen`},{ja: `三時`, pl: `trzecia`, ipa: `san-dźi`},{ja: `遅れます`, pl: `spóźnię się`, ipa: `o-ku-re-mas`},{ja: `大丈夫`, pl: `w porządku`, ipa: `da-i-dzio-o-bu`},{ja: `連絡`, pl: `kontakt / wiadomość`, ipa: `ren-ra-ku`}], phrases: [{ja: `午後三時に会いましょう。`, pl: `Spotkajmy się o trzeciej po południu.`, ipa: `go-go san-dźi ni a-i-ma-szo-o`},{ja: `場所はどこですか。`, pl: `Gdzie jest miejsce?`, ipa: `ba-szio wa do-ko des ka`},{ja: `ハチ公前で会いましょう。`, pl: `Spotkajmy się przed Hachikō.`, ipa: `ha-czi-ko-o ma-e de a-i-ma-szo-o`},{ja: `少し遅れます。`, pl: `Trochę się spóźnię.`, ipa: `su-ko-szi o-ku-re-mas`},{ja: `大丈夫です。`, pl: `W porządku.`, ipa: `da-i-dzio-o-bu des`},{ja: `あとで連絡します。`, pl: `Skontaktuję się później.`, ipa: `a-to-de ren-ra-ku szi-mas`}], grammar: `ましょう oznacza propozycję „zróbmy”. 会いましょう to „spotkajmy się”. Przy konkretnych godzinach używa się に, a przy miejscu spotkania で. 少し遅れます jest uprzejmym i krótkim sposobem poinformowania o spóźnieniu.`, practice: [`Zaproponuj spotkanie o trzeciej po południu.`,`Zapytaj, gdzie jest miejsce spotkania.`,`Powiedz, że trochę się spóźnisz.`,`Powiedz, że wszystko w porządku.`,`Powiedz, że skontaktujesz się później.`]},{day: 26, title: `Wymagania dietetyczne i alergie`, title_native: `食事制限とアレルギー`, focus: `Nauczysz się mówić o alergiach i preferencjach jedzeniowych. W Japonii warto jasno pytać o składniki, szczególnie przy owocach morza, mięsie i sosach.`, vocab: [{ja: `アレルギー`, pl: `alergia`, ipa: `a-rerugii`},{ja: `肉`, pl: `mięso`, ipa: `ni-ku`},{ja: `魚`, pl: `ryba`, ipa: `sa-ka-na`},{ja: `卵`, pl: `jajko`, ipa: `ta-ma-go`},{ja: `乳製品`, pl: `nabiał`, ipa: `njū-se-e-hin`},{ja: `小麦`, pl: `pszenica`, ipa: `ko-mu-gi`},{ja: `野菜`, pl: `warzywa`, ipa: `ja-sa-i`},{ja: `入っています`, pl: `zawiera / jest w środku`, ipa: `ha-it-te i-mas`},{ja: `食べられません`, pl: `nie mogę jeść`, ipa: `ta-be-ra-re-ma-sen`},{ja: `大丈夫`, pl: `w porządku`, ipa: `da-i-dzio-o-bu`}], phrases: [{ja: `肉は食べられません。`, pl: `Nie mogę jeść mięsa.`, ipa: `ni-ku wa ta-be-ra-re-ma-sen`},{ja: `魚は大丈夫です。`, pl: `Ryba jest w porządku.`, ipa: `sa-ka-na wa da-i-dzio-o-bu des`},{ja: `卵が入っていますか。`, pl: `Czy zawiera jajko?`, ipa: `ta-ma-go ga ha-it-te i-mas ka`},{ja: `小麦アレルギーがあります。`, pl: `Mam alergię na pszenicę.`, ipa: `ko-mu-gi a-rerugii ga a-ri-mas`},{ja: `野菜料理はありますか。`, pl: `Czy są dania warzywne?`, ipa: `ja-sa-i rjo-o-ri wa a-ri-mas ka`},{ja: `これは食べられます。`, pl: `Mogę to jeść.`, ipa: `ko-re wa ta-be-ra-re-mas`}], grammar: `食べられません oznacza „nie mogę jeść” albo „nie da się zjeść”. To forma potencjalna w przeczeniu, bardzo ważna przy ograniczeniach dietetycznych. 入っています pyta o składnik zawarty w potrawie. 大丈夫です może znaczyć „jest OK / mogę / nie ma problemu” zależnie od kontekstu.`, practice: [`Powiedz, że nie możesz jeść mięsa.`,`Zapytaj, czy danie zawiera jajko.`,`Powiedz, że masz alergię na pszenicę.`,`Zapytaj o dania warzywne.`,`Powiedz, że możesz to jeść.`]},{day: 27, title: `Poczta i wysyłanie rzeczy`, title_native: `郵便局で荷物を送る`, focus: `Nauczysz się wysyłać pocztówkę lub paczkę. W japońskim urzędzie pocztowym przyda się słownictwo dotyczące adresu, znaczków i przesyłki zagranicznej.`, vocab: [{ja: `郵便局`, pl: `poczta`, ipa: `juu-bin-kjoku`},{ja: `手紙`, pl: `list`, ipa: `te-ga-mi`},{ja: `はがき`, pl: `pocztówka`, ipa: `ha-ga-ki`},{ja: `切手`, pl: `znaczek`, ipa: `kit-te`},{ja: `荷物`, pl: `paczka / bagaż`, ipa: `ni-mo-cu`},{ja: `住所`, pl: `adres`, ipa: `dźiuu-szio`},{ja: `海外`, pl: `zagranica`, ipa: `ka-i-ga-i`},{ja: `航空便`, pl: `poczta lotnicza`, ipa: `ko-o-kuu-bin`},{ja: `船便`, pl: `poczta morska`, ipa: `funa-bin`},{ja: `送ります`, pl: `wysyłam`, ipa: `o-ku-ri-mas`}], phrases: [{ja: `郵便局はどこですか。`, pl: `Gdzie jest poczta?`, ipa: `juu-bin-kjoku wa do-ko des ka`},{ja: `切手をください。`, pl: `Poproszę znaczek.`, ipa: `kit-te o ku-da-sa-i`},{ja: `ポーランドに送りたいです。`, pl: `Chcę wysłać do Polski.`, ipa: `po-o-ran-do ni o-ku-ri-ta-i des`},{ja: `航空便でお願いします。`, pl: `Pocztą lotniczą poproszę.`, ipa: `ko-o-kuu-bin de o-ne-ga-i szi-mas`},{ja: `住所を書きます。`, pl: `Piszę adres.`, ipa: `dźiuu-szio o ka-ki-mas`},{ja: `この荷物を送りたいです。`, pl: `Chcę wysłać tę paczkę.`, ipa: `ko-no ni-mo-cu o o-ku-ri-ta-i des`}], grammar: `に przy wysyłaniu wskazuje miejsce docelowe: ポーランドに送ります. で przy metodzie oznacza „za pomocą / sposobem”, dlatego 航空便で znaczy „pocztą lotniczą”. 書きます oznacza „piszę”. W urzędzie pocztowym najlepiej mówić jasno: rzecz + を + 送りたいです.`, practice: [`Zapytaj, gdzie jest poczta.`,`Poproś o znaczek.`,`Powiedz, że chcesz wysłać coś do Polski.`,`Poproś o pocztę lotniczą.`,`Powiedz, że piszesz adres.`]},{day: 28, title: `Bankomat i płatności`, title_native: `ATMと支払い`, focus: `Nauczysz się mówić o gotówce, karcie i bankomacie. W Japonii gotówka nadal bywa przydatna, zwłaszcza w małych restauracjach i świątyniach.`, vocab: [{ja: `ATM`, pl: `bankomat`, ipa: `e-e-tii-emu`},{ja: `現金`, pl: `gotówka`, ipa: `gen-kin`},{ja: `カード`, pl: `karta`, ipa: `ka-a-do`},{ja: `クレジットカード`, pl: `karta kredytowa`, ipa: `ku-re-dzit-to ka-a-do`},{ja: `支払い`, pl: `płatność`, ipa: `szi-ha-ra-i`},{ja: `払います`, pl: `płacę`, ipa: `ha-ra-i-mas`},{ja: `引き出します`, pl: `wypłacam`, ipa: `hi-ki-da-szi-mas`},{ja: `両替`, pl: `wymiana waluty`, ipa: `rjo-o-ga-e`},{ja: `使えます`, pl: `można użyć`, ipa: `cu-ka-e-mas`},{ja: `手数料`, pl: `opłata / prowizja`, ipa: `te-suu-rjo-o`}], phrases: [{ja: `ATMはどこですか。`, pl: `Gdzie jest bankomat?`, ipa: `e-e-tii-emu wa do-ko des ka`},{ja: `現金で払います。`, pl: `Zapłacę gotówką.`, ipa: `gen-kin de ha-ra-i-mas`},{ja: `カードで払えますか。`, pl: `Czy można zapłacić kartą?`, ipa: `ka-a-do de ha-ra-e-mas ka`},{ja: `お金を引き出したいです。`, pl: `Chcę wypłacić pieniądze.`, ipa: `o-ka-ne o hi-ki-da-szi-ta-i des`},{ja: `手数料はいくらですか。`, pl: `Ile wynosi prowizja?`, ipa: `te-suu-rjo-o wa i-ku-ra des ka`},{ja: `両替できますか。`, pl: `Czy można wymienić walutę?`, ipa: `rjo-o-ga-e de-ki-mas ka`}], grammar: `で wskazuje sposób płatności: 現金で, カードで. 払えますか to forma możliwości od 払います i oznacza „czy można zapłacić?”. たいです ponownie służy do wyrażania chęci, na przykład 引き出したいです. W Japonii warto mieć pod ręką zarówno kartę, jak i gotówkę.`, practice: [`Zapytaj, gdzie jest bankomat.`,`Powiedz, że zapłacisz gotówką.`,`Zapytaj, czy można zapłacić kartą.`,`Powiedz, że chcesz wypłacić pieniądze.`,`Zapytaj o prowizję.`]},{day: 29, title: `Opinie i proste emocje`, title_native: `感想と気持ち`, focus: `Nauczysz się opisywać wrażenia z podróży i swoje samopoczucie. Przyda się to podczas rozmów z gospodarzami, lokalnymi osobami lub innymi podróżnikami.`, vocab: [{ja: `楽しい`, pl: `fajne / przyjemne`, ipa: `ta-no-szii`},{ja: `面白い`, pl: `ciekawe / zabawne`, ipa: `o-mo-szi-ro-i`},{ja: `すばらしい`, pl: `wspaniałe`, ipa: `su-ba-ra-szii`},{ja: `疲れた`, pl: `zmęczony`, ipa: `cu-ka-re-ta`},{ja: `嬉しい`, pl: `szczęśliwy / zadowolony`, ipa: `u-re-szii`},{ja: `心配`, pl: `zmartwienie`, ipa: `szin-pa-i`},{ja: `安心`, pl: `ulga / spokój`, ipa: `an-szin`},{ja: `好き`, pl: `lubię`, ipa: `su-ki`},{ja: `嫌い`, pl: `nie lubię`, ipa: `ki-ra-i`},{ja: `もう一度`, pl: `jeszcze raz`, ipa: `mo-o i-czi-do`}], phrases: [{ja: `とても楽しいです。`, pl: `Jest bardzo przyjemnie.`, ipa: `to-te-mo ta-no-szii des`},{ja: `少し疲れました。`, pl: `Trochę się zmęczyłem/zmęczyłam.`, ipa: `su-ko-szi cu-ka-re-ma-szi-ta`},{ja: `日本が好きです。`, pl: `Lubię Japonię.`, ipa: `ni-hon ga su-ki des`},{ja: `これは面白いです。`, pl: `To jest ciekawe.`, ipa: `ko-re wa o-mo-szi-ro-i des`},{ja: `安心しました。`, pl: `Ulżyło mi.`, ipa: `an-szin szi-ma-szi-ta`},{ja: `もう一度行きたいです。`, pl: `Chcę pójść jeszcze raz.`, ipa: `mo-o i-czi-do i-ki-ta-i des`}], grammar: `とても wzmacnia przymiotnik i znaczy „bardzo”. 少し łagodzi wypowiedź i znaczy „trochę”. Czas przeszły w formie grzecznej często kończy się na ました, jak 疲れました. Uczucia po japońsku często wyrażane są przymiotnikami lub rzeczownikami z しました.`, practice: [`Powiedz, że jest bardzo przyjemnie.`,`Powiedz, że trochę się zmęczyłeś.`,`Powiedz, że lubisz Japonię.`,`Powiedz, że coś jest ciekawe.`,`Powiedz, że chcesz pójść jeszcze raz.`]},{day: 30, title: `Podsumowanie podróży i pewna komunikacja`, title_native: `旅行のまとめと自信`, focus: `Połączysz najważniejsze zwroty z całego kursu w praktyczne mini-dialogi. Wyobraź sobie ostatni dzień w Tokio: wymeldowanie, zakupy, transport na lotnisko i pożegnanie.`, vocab: [{ja: `旅行`, pl: `podróż`, ipa: `rjo-ko-o`},{ja: `最後`, pl: `ostatni`, ipa: `sa-i-go`},{ja: `空港`, pl: `lotnisko`, ipa: `kuu-ko-o`},{ja: `思い出`, pl: `wspomnienie`, ipa: `o-mo-i-de`},{ja: `便利`, pl: `wygodne / praktyczne`, ipa: `ben-ri`},{ja: `親切`, pl: `uprzejmy / życzliwy`, ipa: `szin-se-cu`},{ja: `また`, pl: `znowu`, ipa: `ma-ta`},{ja: `帰ります`, pl: `wracam`, ipa: `ka-e-ri-mas`},{ja: `ありがとうございました`, pl: `dziękuję bardzo za to, co było`, ipa: `a-ri-ga-to-o go-za-i-ma-szi-ta`},{ja: `気をつけて`, pl: `uważaj na siebie`, ipa: `ki o cu-ke-te`}], phrases: [{ja: `今日は最後の日です。`, pl: `Dziś jest ostatni dzień.`, ipa: `kjo-o wa sa-i-go no hi des`},{ja: `空港までお願いします。`, pl: `Na lotnisko poproszę.`, ipa: `kuu-ko-o ma-de o-ne-ga-i szi-mas`},{ja: `日本は便利です。`, pl: `Japonia jest wygodna.`, ipa: `ni-hon wa ben-ri des`},{ja: `皆さんは親切でした。`, pl: `Wszyscy byli życzliwi.`, ipa: `mi-na-san wa szin-se-cu de-szi-ta`},{ja: `また来たいです。`, pl: `Chcę przyjechać znowu.`, ipa: `ma-ta ki-ta-i des`},{ja: `ありがとうございました。`, pl: `Dziękuję bardzo.`, ipa: `a-ri-ga-to-o go-za-i-ma-szi-ta`}], grammar: `でした to grzeczna forma przeszła od です. 親切でした znaczy „był/była/byli życzliwi”. たいです może dotyczyć także przyszłych planów, na przykład また来たいです. ありがとうございました jest formą podziękowania za coś, co już się wydarzyło, dlatego dobrze pasuje na koniec pobytu.`, practice: [`Powiedz, że dziś jest ostatni dzień.`,`Poproś o kurs na lotnisko.`,`Powiedz, że Japonia jest wygodna.`,`Powiedz, że wszyscy byli życzliwi.`,`Powiedz, że chcesz przyjechać znowu.`]}];

var CONVERSATIONS_PL_JA = [{id: 1, title: `Zamawianie kawy w kawiarni`, scene: `Jesteś w małej kawiarni w Fukuoce. Chcesz zamówić ciepłą kawę, zapytać o cukier i zapłacić kartą.`, lines: [{who: `them`, ja: `いらっしゃいませ。`, pl: `Witamy.`},{who: `you`, ja: `こんにちは。コーヒーをください。`, pl: `Dzień dobry. Poproszę kawę.`},{who: `them`, ja: `温かいコーヒーですか。`, pl: `Ciepłą kawę?`},{who: `you`, ja: `はい、温かいコーヒーをお願いします。`, pl: `Tak, poproszę ciepłą kawę.`},{who: `them`, ja: `サイズはどうしますか。`, pl: `Jaki rozmiar?`},{who: `you`, ja: `小さいサイズでお願いします。`, pl: `Poproszę mały rozmiar.`},{who: `them`, ja: `砂糖はいりますか。`, pl: `Czy potrzebny jest cukier?`},{who: `you`, ja: `いいえ、砂糖はいりません。`, pl: `Nie, nie potrzebuję cukru.`},{who: `them`, ja: `お会計は三百円です。`, pl: `Rachunek wynosi 300 jenów.`},{who: `you`, ja: `カードで払えますか。`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, ja: `はい、大丈夫です。`, pl: `Tak, w porządku.`},{who: `you`, ja: `ありがとうございます。`, pl: `Dziękuję bardzo.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz do hotelu w Kanazawie po długiej podróży. Masz rezerwację i chcesz zapytać o śniadanie oraz zostawienie bagażu.`, lines: [{who: `them`, ja: `こんばんは。チェックインですか。`, pl: `Dobry wieczór. Zameldowanie?`},{who: `you`, ja: `はい、チェックインをお願いします。`, pl: `Tak, poproszę o zameldowanie.`},{who: `them`, ja: `お名前は何ですか。`, pl: `Jakie jest nazwisko?`},{who: `you`, ja: `名前はコヴァルスキです。`, pl: `Nazwisko to Kowalski.`},{who: `them`, ja: `予約があります。パスポートをお願いします。`, pl: `Jest rezerwacja. Poproszę paszport.`},{who: `you`, ja: `はい、パスポートです。`, pl: `Tak, oto paszport.`},{who: `them`, ja: `お部屋は三階です。`, pl: `Pokój jest na trzecim piętrze.`},{who: `you`, ja: `朝食はありますか。`, pl: `Czy jest śniadanie?`},{who: `them`, ja: `はい、朝七時からです。`, pl: `Tak, od siódmej rano.`},{who: `you`, ja: `荷物を預けたいです。`, pl: `Chcę zostawić bagaż.`},{who: `them`, ja: `はい、大丈夫です。`, pl: `Tak, w porządku.`},{who: `you`, ja: `ありがとうございます。`, pl: `Dziękuję bardzo.`}]},{id: 3, title: `Pytanie o drogę do stacji`, scene: `Jesteś w Sapporo i nie możesz znaleźć stacji metra. Zatrzymujesz przechodnia i pytasz o kierunek.`, lines: [{who: `you`, ja: `すみません。駅はどこですか。`, pl: `Przepraszam. Gdzie jest stacja?`},{who: `them`, ja: `駅はあそこです。`, pl: `Stacja jest tam dalej.`},{who: `you`, ja: `近いですか。`, pl: `Czy jest blisko?`},{who: `them`, ja: `はい、近いです。`, pl: `Tak, jest blisko.`},{who: `you`, ja: `どう行きますか。`, pl: `Jak tam dojść?`},{who: `them`, ja: `まっすぐ行ってください。`, pl: `Proszę iść prosto.`},{who: `you`, ja: `右ですか、左ですか。`, pl: `W prawo czy w lewo?`},{who: `them`, ja: `次の角を右に行ってください。`, pl: `Na następnym rogu proszę skręcić w prawo.`},{who: `you`, ja: `ありがとうございます。`, pl: `Dziękuję bardzo.`},{who: `them`, ja: `どういたしまして。`, pl: `Nie ma za co.`},{who: `you`, ja: `助かりました。`, pl: `Bardzo mi pan/pani pomógł/pomogła.`},{who: `them`, ja: `気をつけて。`, pl: `Proszę uważać na siebie.`}]},{id: 4, title: `Obiad w restauracji w Osace`, scene: `Wchodzisz do restauracji w Osace, gdzie chcesz spróbować lokalnego jedzenia. Pytasz o polecenie i zamawiasz danie.`, lines: [{who: `them`, ja: `いらっしゃいませ。何名様ですか。`, pl: `Witamy. Ile osób?`},{who: `you`, ja: `一人です。`, pl: `Jedna osoba.`},{who: `them`, ja: `こちらへどうぞ。`, pl: `Tędy proszę.`},{who: `you`, ja: `メニューをください。`, pl: `Poproszę menu.`},{who: `them`, ja: `はい、どうぞ。`, pl: `Tak, proszę.`},{who: `you`, ja: `おすすめは何ですか。`, pl: `Co pan/pani poleca?`},{who: `them`, ja: `お好み焼きがおすすめです。`, pl: `Polecam okonomiyaki.`},{who: `you`, ja: `辛いですか。`, pl: `Czy to jest ostre?`},{who: `them`, ja: `いいえ、辛くないです。`, pl: `Nie, nie jest ostre.`},{who: `you`, ja: `では、お好み焼きをください。`, pl: `W takim razie poproszę okonomiyaki.`},{who: `them`, ja: `はい、少々お待ちください。`, pl: `Dobrze, proszę chwilę poczekać.`},{who: `you`, ja: `お願いします。`, pl: `Proszę.`}]},{id: 5, title: `Kupowanie biletu na Shinkansen`, scene: `Jesteś na dużym dworcu w Tokio i chcesz kupić bilet do Kioto. Pytasz o miejsce przy oknie oraz godzinę przyjazdu.`, lines: [{who: `them`, ja: `こんにちは。どちらまでですか。`, pl: `Dzień dobry. Dokąd?`},{who: `you`, ja: `京都までお願いします。`, pl: `Do Kioto poproszę.`},{who: `them`, ja: `片道ですか、往復ですか。`, pl: `W jedną stronę czy w obie strony?`},{who: `you`, ja: `片道です。`, pl: `W jedną stronę.`},{who: `them`, ja: `指定席ですか。`, pl: `Miejsce rezerwowane?`},{who: `you`, ja: `はい、指定席をお願いします。`, pl: `Tak, poproszę miejsce rezerwowane.`},{who: `them`, ja: `窓側はいいですか。`, pl: `Czy miejsce przy oknie będzie dobre?`},{who: `you`, ja: `はい、窓側がいいです。`, pl: `Tak, przy oknie będzie dobrze.`},{who: `them`, ja: `到着は午後二時半です。`, pl: `Przyjazd jest o 14:30.`},{who: `you`, ja: `ありがとうございます。いくらですか。`, pl: `Dziękuję. Ile kosztuje?`},{who: `them`, ja: `一万四千円です。`, pl: `14 000 jenów.`},{who: `you`, ja: `カードで払います。`, pl: `Zapłacę kartą.`}]},{id: 6, title: `Zakupy pamiątek w Kioto`, scene: `W sklepie z pamiątkami w Kioto oglądasz małe prezenty. Chcesz zapytać o cenę, kolor i płatność kartą.`, lines: [{who: `them`, ja: `いらっしゃいませ。`, pl: `Witamy.`},{who: `you`, ja: `こんにちは。これを見てもいいですか。`, pl: `Dzień dobry. Czy mogę to obejrzeć?`},{who: `them`, ja: `はい、どうぞ。`, pl: `Tak, proszę.`},{who: `you`, ja: `これはいくらですか。`, pl: `Ile to kosztuje?`},{who: `them`, ja: `千二百円です。`, pl: `1200 jenów.`},{who: `you`, ja: `赤いものはありますか。`, pl: `Czy jest coś czerwonego?`},{who: `them`, ja: `はい、こちらです。`, pl: `Tak, tutaj.`},{who: `you`, ja: `きれいですね。`, pl: `Piękne, prawda?`},{who: `them`, ja: `はい、京都のお土産です。`, pl: `Tak, to pamiątka z Kioto.`},{who: `you`, ja: `これをください。`, pl: `Poproszę to.`},{who: `them`, ja: `お支払いは現金ですか。`, pl: `Płatność gotówką?`},{who: `you`, ja: `カードで払えますか。`, pl: `Czy mogę zapłacić kartą?`}]},{id: 7, title: `W aptece z bólem gardła`, scene: `W Nagoi zaczyna boleć cię gardło. Wchodzisz do apteki, żeby wyjaśnić objawy i poprosić o lekarstwo.`, lines: [{who: `them`, ja: `こんにちは。どうしましたか。`, pl: `Dzień dobry. Co się stało?`},{who: `you`, ja: `喉が痛いです。`, pl: `Boli mnie gardło.`},{who: `them`, ja: `熱がありますか。`, pl: `Czy ma pan/pani gorączkę?`},{who: `you`, ja: `いいえ、熱はありません。`, pl: `Nie, nie mam gorączki.`},{who: `them`, ja: `風邪かもしれません。`, pl: `To może być przeziębienie.`},{who: `you`, ja: `薬をください。`, pl: `Poproszę lekarstwo.`},{who: `them`, ja: `アレルギーはありますか。`, pl: `Czy ma pan/pani alergie?`},{who: `you`, ja: `小麦アレルギーがあります。`, pl: `Mam alergię na pszenicę.`},{who: `them`, ja: `わかりました。この薬は大丈夫です。`, pl: `Rozumiem. To lekarstwo jest w porządku.`},{who: `you`, ja: `ありがとうございます。いくらですか。`, pl: `Dziękuję. Ile kosztuje?`},{who: `them`, ja: `八百円です。`, pl: `800 jenów.`},{who: `you`, ja: `現金で払います。`, pl: `Zapłacę gotówką.`}]},{id: 8, title: `Small talk z lokalną osobą w pociągu`, scene: `Jedziesz pociągiem z Kioto do Nary i osoba obok zaczyna przyjazną rozmowę. Odpowiadasz prosto, mówiąc skąd jesteś i co lubisz w Japonii.`, lines: [{who: `you`, ja: `こんにちは。ここは空いていますか。`, pl: `Dzień dobry. Czy to miejsce jest wolne?`},{who: `them`, ja: `はい、空いています。どうぞ。`, pl: `Tak, jest wolne. Proszę.`},{who: `you`, ja: `ありがとうございます。`, pl: `Dziękuję bardzo.`},{who: `them`, ja: `どちらの出身ですか。`, pl: `Skąd pan/pani pochodzi?`},{who: `you`, ja: `ポーランド出身です。`, pl: `Pochodzę z Polski.`},{who: `them`, ja: `日本語が上手ですね。`, pl: `Dobrze mówi pan/pani po japońsku.`},{who: `you`, ja: `ありがとうございます。日本語を少し話します。`, pl: `Dziękuję. Mówię trochę po japońsku.`},{who: `them`, ja: `日本は楽しいですか。`, pl: `Czy Japonia jest przyjemna?`},{who: `you`, ja: `はい、とても楽しいです。`, pl: `Tak, jest bardzo przyjemna.`},{who: `them`, ja: `何が好きですか。`, pl: `Co pan/pani lubi?`},{who: `you`, ja: `寺と食べ物が好きです。`, pl: `Lubię świątynie i jedzenie.`},{who: `them`, ja: `いいですね。奈良もすばらしいです。`, pl: `To dobrze. Nara też jest wspaniała.`}]}];